window.__QUIZ_DATA__=[{"id":"objective>Physics>2006>1","subject":"Physics","year":"2006","type":"Objective","topic":"DESCRIPTION PROPERTY OF FIELDS : CONCEPT OF FIELDS","question":"Which of the following phenomena causes capillarity of liquids in tubes of narrow bore?","images":[],"options":{"A":"Viscosity","B":"Surface tension","C":"Osmosis","D":"Brownian motion"},"answer":"B","explanation":"Surface tension causes the capillarity of liquids in tubes of narrow bore. Surface tension is the tension or force acting parallel to the surface of a liquid.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>2","subject":"Physics","year":"2006","type":"Objective","topic":"FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : DERIVED QUANTITIES AND UNITS","question":"Which of the following physical quantities are derived?  I. Area II. Thrust III. Pressure IV. Mass","images":[],"options":{"A":"I, II, III and IV","B":"I, II and III only","C":"I, II and IV only","D":"I and III only"},"answer":"B","explanation":"Derived quantities are those quantities which are produced from the combination of base quantities through multiplication or division. Area is derived from length x width, Thrust is derived from mass x acceleration, and Pressure is derived from force/area. However, Mass is a fundamental or base quantity, not a derived quantity. Therefore, the correct answer is I, II and III only.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>3","subject":"Physics","year":"2006","type":"Objective","topic":"FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES\u2019 PRINCIPLE","question":"A block of volume 3 \u00d7 105m3 and density 2.5 \u00d7 103kg m-3 is suspended from a spring balance with 2/3 of its volume immersed in a liquid of density 900kg m-3. Determine the reading of the spring balance. [g = 10ms-2]","images":[],"options":{"A":"0.18 \u00d7 1010N","B":"0.57 \u00d7 1010N","C":"0.75 \u00d7 1010N","D":"0.93 \u00d7 1010N"},"answer":"B","explanation":"Volume of block = 3 \u00d7 105m3  Density of block = 2.5 \u00d7 103 kgm-3  Volume immersed in the liquid = 2/3 \u00d7 3 \u00d7 105 m3  Density of the liquid = 900kgm-3  Weight in the liquid = ?  Upthrust experienced in the liquid = 2/3 \u00d7 3 \u00d7 105 \u00d7 900 \u00d7 10 = 1.8 \u00d7 109  The weight of the block in air = 3 \u00d7 105 \u00d7 2.5 \u00d7 103 \u00d7 10 = 7.5 \u00d7 109  The tension, T in the spring balance = Weight of the block in liquid   T = W - U  T = (7.5 - 1.8)109N  T = 5.7 \u00d7 109 N","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>4","subject":"Physics","year":"2006","type":"Objective","topic":"FLUID AT REST : EQUILIBRIUM OF BODIES: LAW OF FLOTATION","question":"A solid body will float in a liquid if its","images":[],"options":{"A":"density is less than that of the liquid","B":"mass is equal to that of the liquid","C":"density is greater than that of the liquid","D":"mass is less than that of the liquid"},"answer":"A","explanation":"According to Archimedes' principle, a solid body will float in a liquid if its density is less than that of the liquid. This is because the upthrust or buoyant force exerted by the liquid on the solid body is greater than the weight of the solid body, causing it to float.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>5","subject":"Physics","year":"2006","type":"Objective","topic":"SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)","question":"An object is said to undergo oscillatory motion when it moves","images":[],"options":{"A":"in an erratic manner","B":"to and fro about a fixed point","C":"in a circular path","D":"along a continuous path from the starting point"},"answer":"B","explanation":"Oscillatory motion is a type of motion in which an object moves to and fro about a fixed point. This is often seen in pendulums and springs.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>6","subject":"Physics","year":"2006","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A moving car of mass 800kg experiences a frictional force of 200N. If it accelerates at 2ms-2, calculate the magnitude of the force applied to the car.","images":[],"options":{"A":"600N","B":"1000N","C":"1600N","D":"1800N"},"answer":"D","explanation":"Given:  The mass of the car = 800kg  The Frictional Force = 200N  Acceleration = 2ms-2  Force applied = F  \u2234 Net Force on the car = mass \u00d7 acceleration  F - 200 = 800 \u00d7 2  F - 200 = 1600  F = 1800N","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>7","subject":"Physics","year":"2006","type":"Objective","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"A body is rotating in a horizontal circle of radius 2.5m with and angular speed of 5 rads-1. Calculate the magnitude of the radial acceleration of the body.","images":[],"options":{"A":"62.50 ms-2","B":"31.25 ms-2","C":"12.50 ms-2","D":"10.00 ms-2"},"answer":"A","explanation":"Given:  The radius of the circle = 2.5m  Angular speed, \u03c9 = 5 rads-1  Radial acceleration, a = a  Recall that: a = \u03c92r   a = (5)2 \u00d7 2.5 = 25 \u00d7 2.5 = 62.5ms-2","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>8","subject":"Physics","year":"2006","type":"Objective","topic":"SPEED AND VELOCITY : CONCEPT OF SPEED","question":"Uniform speed occurs when there is equal change of","images":[],"options":{"A":"distance in equal times","B":"displacement in equal times","C":"velocity in equal times","D":"acceleration in equal times"},"answer":"A","explanation":"Uniform speed refers to the condition where an object covers equal distances in equal intervals of time. This is different from uniform velocity, which would require both equal speed and constant direction.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>9","subject":"Physics","year":"2006","type":"Objective","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"A car accelerates uniformly from rest at 5ms-2. Determine its speed after 10s.","images":[],"options":{"A":"50.0ms-1","B":"25.0 ms-1","C":"2.0ms-1","D":"0.5ms-1"},"answer":"A","explanation":"Acceleration, a = 5ms-2  Initial velocity, U = 0  Final velocity = V ; Time = t = 10s  Recall: V = u + at ; V = 0 + 5(10)  V = 50ms-1","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>10","subject":"Physics","year":"2006","type":"Objective","topic":"SPEED AND VELOCITY : DISTANCE/DISPLACEMENT-TIME GRAPH","question":"The diagram above shows the speed-time graph of a car. If the car covered a total distance of 600m in 25s, calculate its maximum speed.","images":["data:image/png;base64,"],"options":{"A":"30 ms-1","B":"25 ms-1","C":"20 ms-1","D":"15 ms-1"},"answer":"A","explanation":"Given: The velocity-time graph  600=12\u00d75\u00d7Vmax+15\u00d7Vmax+12\u00d75\u00d7Vmax  600=Vmax(12\u00d75+15+12\u00d75)  600 = Vmax (20)  Vmax = 30ms-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>11","subject":"Physics","year":"2006","type":"Objective","topic":"SCALARS AND VECTORS : CONCEPT OF VECTORS","question":"Which of the following quantities is a vector?","images":[],"options":{"A":"Speed","B":"Distance","C":"Energy","D":"Momentum"},"answer":"D","explanation":"A vector quantity is one that has both magnitude (size) and direction. Of the options given, only momentum is a vector quantity. Momentum is the product of an object's mass and its velocity, and it has a direction (the same as the direction of the velocity). Speed, distance, and energy are all scalar quantities, meaning they have magnitude but no direction.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>12","subject":"Physics","year":"2006","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"Determine the magnitude of P in the diagram above.","images":["data:image/png;base64,"],"options":{"A":"16N","B":"20N","C":"32N","D":"40N"},"answer":"C","explanation":"Given: The diagram in the question   Pcos60\u00b0 \u00d7 50 = 40 \u00d7 20  0.5P \u00d7 50 = 800  25P = 800  P = 32N","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>13","subject":"Physics","year":"2006","type":"Objective","topic":"SIMPLE HARMONIC MOTION : ENERGY OF S.H.M","question":"Which of the following statements about smile harmonic motion is correct? The","images":[],"options":{"A":"total mechanical energy is always conserved","B":"linear acceleration is directed to any variable point","C":"linear acceleration varies inversely with displacement","D":"period of oscillation varies linearly as acceleration due to gravity"},"answer":"A","explanation":"In simple harmonic motion, the total mechanical energy is always conserved. This is because the sum of kinetic and potential energy remains constant throughout the motion. The other options are incorrect. The linear acceleration is always directed towards the equilibrium position, not any variable point. The linear acceleration does not vary inversely with displacement, but is directly proportional to the displacement. The period of oscillation does not vary linearly with acceleration due to gravity, but is independent of it.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>14","subject":"Physics","year":"2006","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A force on a body causes a change in the momentum of the body from 12 kg ms-1 to 16 kg ms-1 in 0.2 s. Calculate the magnitude of the impulse","images":[],"options":{"A":"28.0 Ns","B":"20.0 Ns","C":"4.0 Ns","D":"0.8 Ns"},"answer":"C","explanation":"Given: The initial momentum, P1 = 12kg ms-1  The final momentum, P2 = 16kgms-1  The time taken for the change to take place = 0.25s.  Recall that Impulse = Ft = \u0394 P  \u2234 Impulse = \u0394P = P2 - P1  Impulse = 16 - 12 = 4kgms-1 = 4Ns","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>15","subject":"Physics","year":"2006","type":"Objective","topic":"ENERGY : WORLD ENERGY RESOURCES","question":"Which of the following sources of energy is renewable?","images":[],"options":{"A":"Petroleum","B":"Charcoal","C":"Hydro","D":"Nuclear"},"answer":"C","explanation":"Hydro energy is a renewable source of energy. It is derived from the movement of water and can be replenished naturally. On the other hand, petroleum, charcoal, and nuclear energy are non-renewable sources of energy. They cannot be replenished on a human timescale and their reserves are finite.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>16","subject":"Physics","year":"2006","type":"Objective","topic":"WORK, ENERGY AND POWER : TYPES OF MECHANICAL ENERGY: POTENTIAL ENERGY AND KINETIC ENERGY","question":"A stone of mass 2.0 kg is thrown vertically upwards with a velocity of 20 ms-1, calculate the initial kinetic energy of the stone.","images":[],"options":{"A":"200 J","B":"400 J","C":"800 J","D":"1600 J"},"answer":"B","explanation":"Given:  The mass of the stone = 2.0kg  Velocity of throw, u = 20.0ms-1  Totalkineticenergy=12mu2  = 1/2 \u00d7 2 \u00d7 (20)2  = 400Nm or 400J","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>17","subject":"Physics","year":"2006","type":"Objective","topic":"SOUND WAVES : SOURCES OF SOUND","question":"Which of the following statements about the mouth piece of a telephone is correct? It converts sound energy into","images":[],"options":{"A":"Acoustic Energy","B":"Mechanical Energy","C":"Electrical Energy","D":"Heat Energy"},"answer":"C","explanation":"The mouthpiece of a telephone converts sound energy into electrical energy. This is because the sound waves produced by the speaker's voice cause a diaphragm in the mouthpiece to vibrate. These vibrations are then converted into electrical signals by a process known as transduction.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>18","subject":"Physics","year":"2006","type":"Objective","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"The potential energy in an elastic string of force constant k which has been extended by x metres is expressed as","images":[],"options":{"A":"1/2 kx2","B":"kx2","C":"1/2 kx","D":"kx"},"answer":"A","explanation":"The potential energy in an elastic string of force constant K, which has been extended by x metres = 1/2 kx2.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>19","subject":"Physics","year":"2006","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF POWER","question":"The engine of a train produces a force of 3000N when moving at 30ms-1. Calculate the power of the engine.","images":[],"options":{"A":"1.00 \u00d7 102 W","B":"3.00 \u00d7 104 W","C":"9.00 \u00d7 104 W","D":"3.00 \u00d7 105 W"},"answer":"C","explanation":"The power of an engine is calculated by the formula P = Fv, where P is power, F is force, and v is velocity. Substituting the given values, we get P = 3000N * 30ms-1 = 90000W or 9.00 \u00d7 104 W.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>20","subject":"Physics","year":"2006","type":"Objective","topic":"MACHINES :","question":"The velocity ratio of an inclined plane, inclined at an angle \u03b8 to the horizontal can be expressed as","images":[],"options":{"A":"(sin\u03b8-1)","B":"sin\u03b8","C":"(cos\u03b8)-1","D":"cos\u03b8"},"answer":"A","explanation":"The velocity ratio (VR) of an inclined plane is given by the formula VR = 1/sin\u03b8. This is because the velocity ratio is the ratio of the distance moved by the effort to the distance moved by the load. In an inclined plane, the effort moves along the slope (hypotenuse) while the load moves vertically (opposite side). The ratio of these distances is 1/sin\u03b8.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>21","subject":"Physics","year":"2006","type":"Objective","topic":"MACHINES :","question":"A block and tackle system has six pulleys. A force of 50N applied to it lifts a load of weight W. If the efficiency of the system is 40%, calculate W.","images":[],"options":{"A":"300N","B":"200N","C":"140N","D":"120N"},"answer":"D","explanation":"Given:  The velocity ratio, V.R = Number of pulleys = 6  The Effort, E = 50N  The Load, L = W  Efficiency = 40%  Recall:Efficiency=(LE)\u00d71V.R  \u223440100=W50\u00d716  410=W300  W = 120N","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>22","subject":"Physics","year":"2006","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"The sagging of overhead electrical cables is the consequence of","images":[],"options":{"A":"linear expansivity","B":"superficial expansivity","C":"cubic expansivity","D":"conductivity"},"answer":"A","explanation":"That is a consequence of linear expansivity. An increase in temperature of the wire will cause it to extend in length and this makes it to sag.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>23","subject":"Physics","year":"2006","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"The silvered surface in a vacuum flask reduces heat loss due to","images":[],"options":{"A":"conduction","B":"convection","C":"radiation","D":"evaporation"},"answer":"C","explanation":"The silvered surface in a vacuum flask reduces heat loss due to radiation. Radiation is the transfer of heat by electromagnetic waves. The silvered surface reflects these waves back into the flask, reducing heat loss.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>24","subject":"Physics","year":"2006","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"How long will it take to heat 3 kg of water from 28\u00b0C to 88\u00b0C in an electric kettle taking 6A from a 220V supply?   [Specific Heat Capacity of Water = 4180 J kg-1k-1]","images":[],"options":{"A":"120s","B":"570s","C":"600s","D":"836s"},"answer":"B","explanation":"The mass, m of the water = 3kg.  The heat change, \u0394\u03b8 = 88\u00b0c - 28\u00b0c = 60\u00b0c  The current, I = 6A  The voltage, V = 220V  The SHC of water = 4180Jkg-1k-1; The time, t = unknown  Recall that: Electrical energy = ivt  It should be noted that: Electrical Energy = Thermal Energy   6 \u00d7 220 \u00d7 t = 3 \u00d7 4180 \u00d7 60  1320t = 180 \u00d7 4180  t=180\u00d741801320  t = 180\u00d719\u00d7220/220\u00d76 = 30 \u00d7 19   = 570s.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>25","subject":"Physics","year":"2006","type":"Objective","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION","question":"The amount of energy required to change a kilogram of ice block into water without a change in temperature is","images":[],"options":{"A":"heat capacity of ice","B":"specific heat capacity","C":"specific latent heat of vapourization of ice","D":"specific latent heat of fusion of ice"},"answer":"D","explanation":"The energy required to change a kilogram of ice into water without a change in temperature is known as the specific latent heat of fusion. This is the amount of heat energy required to change 1 kg of a substance from a solid to a liquid (or vice versa) without a change in temperature. Therefore, the correct answer is 'specific latent heat of fusion of ice'.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>26","subject":"Physics","year":"2006","type":"Objective","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION","question":"A quantity of stem at 100\u00b0C condenses to water at the same temperature by releasing 6.9 \u00d7 104J of energy. Calculate the mass of the condensed steam. [ specific latent heat of vapourization of water = 2.3 \u00d7 106 J kg-1]","images":[],"options":{"A":"3.0 \u00d7 10-1 kg","B":"3.0 \u00d7 10-2 kg","C":"3.0 \u00d7 10-3 kg","D":"3.0 \u00d7 10-4 kg"},"answer":"B","explanation":"Given:  The change in temperature = 0\u00b0C (since it is from 100\u00b0C to 100\u00b0C)  The heat energy released, E = 6.9 \u00d7 104J; SLH of vaporization = 2.3 \u00d7 106Jkg-1  The mass of the condensed steam is unknown.  Recall, E = mL  6.9 \u00d7 104 = m \u00d7 2.3 \u00d7 106;  m=6.9\u00d71042.3\u00d7106=3\u00d710-2kg=0.03kg","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>27","subject":"Physics","year":"2006","type":"Objective","topic":"HEAT ENERGY : EVAPORATION AND BOILING","question":"The temperature of a liquid falls after some of it has evaporated because","images":[],"options":{"A":"the liquid left is smaller in volume and the breeze easily cools it.","B":"the more energetic molecules have escaped into the atmosphere","C":"the liquid left has latent heat","D":"after evaporation impurities are left behind"},"answer":"B","explanation":"When a liquid evaporates, it is the more energetic (hotter) molecules that have enough energy to overcome the intermolecular forces and escape into the atmosphere. This leaves behind the less energetic (cooler) molecules, resulting in a decrease in the average kinetic energy of the liquid and hence a decrease in its temperature. Therefore, the correct answer is 'the more energetic molecules have escaped into the atmosphere'.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>28","subject":"Physics","year":"2006","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"The S.I units of frequency, period and amplitude of a wave are respectively","images":[],"options":{"A":"hertz, second and centimetre","B":"second, metre and hertz","C":"metre, hertz and second","D":"hertz, second and metre"},"answer":"D","explanation":"The S.I units of frequency = Hertz   The S.I units of period = second  The S.I units of amplitude = metre","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>29","subject":"Physics","year":"2006","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"A note of frequency 2000Hz has a velocity of 400ms-1, Calculate the wave length of the note.","images":[],"options":{"A":"5.0m","B":"2.0m","C":"0.5m","D":"0.2m"},"answer":"D","explanation":"Frequency, f = 2000Hz  Velocity, v = 400ms-1  Wavelength, \u03bb = ?  Recall that: v = f\u03bb  \u2234 400 = \u03bb \u00d7 2000  \u03bb=4002000  \u03bb = 0.2 m","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>30","subject":"Physics","year":"2006","type":"Objective","topic":"LIGHT WAVES : RECTILINEAR PROPAGATION OF LIGHT","question":"The eclipse of the moon occurs when the","images":[],"options":{"A":"moon comes exactly between the earth and the sun","B":"earth comes exactly between the moon and the sun","C":"sun comes exactly between the earth and the moon","D":"moon reflects all the rays from the sun onto the earth"},"answer":"B","explanation":"An eclipse of the moon, or a lunar eclipse, occurs when the Earth comes exactly between the moon and the sun. This causes the Earth's shadow to fall on the moon, making it appear dark from our perspective. Therefore, the correct answer is 'earth comes exactly between the moon and the sun'.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>31","subject":"Physics","year":"2006","type":"Objective","topic":"LIGHT WAVES : RECTILINEAR PROPAGATION OF LIGHT","question":"Which of the following observations cannot be explained using the rectilinear propagation of light?","images":[],"options":{"A":"Production of images by a pinhole camera","B":"Production of real images of objects by lenses","C":"Formation of an annular eclipse","D":"Diffraction patterns of light"},"answer":"D","explanation":"The rectilinear propagation of light refers to the principle that light travels in straight lines. This principle explains the production of images by a pinhole camera and the production of real images of objects by lenses. However, it does not explain the formation of diffraction patterns of light. Diffraction is a wave property of light that involves the bending of light waves around obstacles or the spreading of light waves after they pass through a small opening. This phenomenon cannot be explained by the rectilinear propagation of light.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>32","subject":"Physics","year":"2006","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"The distance between the successive crests of a wave travelling at 20 ms-1 is 25 cm. Calculate the frequency of the wave.","images":[],"options":{"A":"0.8 Hz","B":"5.0 Hz","C":"50.0 Hz","D":"80.0 Hz"},"answer":"D","explanation":"- The distance between two successive crest = Wavelength = 25cm = 0.25m  - The velocity, V of the wave = 20ms-1  Frequency, f is unknown   Recall, v = f\u03bb  20 = f \u00d7 0.25  f = 80Hz","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>33","subject":"Physics","year":"2006","type":"Objective","topic":"LIGHT WAVES : PLANE MIRROR","question":"A ray from a fixed object is incident on a plane mirror at an angle of 20\u00b0. If the mirror is rotated through 30\u00b0, by how many degrees would the reflect ray rotate?","images":[],"options":{"A":"60o","B":"50o","C":"40o","D":"30o"},"answer":"B","explanation":"The reflected ray would rotate through an angle of 20\u00b0 + 30\u00b0 = 50\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>34","subject":"Physics","year":"2006","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"Which of the following distances is usually adjustable in the camera? The distance between the","images":[],"options":{"A":"lens and the film","B":"diaphragm and the shutter","C":"shutter and the film","D":"diaphragm and the film"},"answer":"A","explanation":"In a camera, the distance that is usually adjustable is the distance between the lens and the film. This is because adjusting this distance allows for the focusing of the image on the film.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>35","subject":"Physics","year":"2006","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"A travelling microscope is focussed on a mark on a table. If a glass block of thickness 18.0cm is placed on the mark, by how many centimetres will the microscope be moved upwards so as to focus the mark once again?  [refractive index of glass = 1.5]","images":[],"options":{"A":"27cm","B":"24cm","C":"9cm","D":"6cm"},"answer":"D","explanation":"Apparentdepth=thicknessrefractiveindex   =181.5=12cm  Upward adjustment = 18 - 12 = 6cm","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>36","subject":"Physics","year":"2006","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"In which of the following media would sound wave travel fastest?","images":[],"options":{"A":"Wood","B":"Water","C":"Iron","D":"Mercury"},"answer":"C","explanation":"The speed of sound in a medium is determined by the medium's elasticity and density. Sound travels faster in solids than in liquids or gases because molecules in a solid medium are closer together and can more easily transfer vibration energy. Among the given options, iron, being a solid, would allow sound waves to travel fastest.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>37","subject":"Physics","year":"2006","type":"Objective","topic":"SOUND WAVES : VIBRATION IN STRINGS","question":"Which of the following actions is necessary in order to tune a string to produce a note of an octave higher than its fundamental?","images":[],"options":{"A":"Doubling the length of the string","B":"Reducing the tension by half","C":"Reducing the mass per unit length","D":"Increasing the tension four times"},"answer":"C","explanation":"The frequency of a vibrating string is inversely proportional to its length and directly proportional to the square root of its tension. It is also inversely proportional to the square root of its mass per unit length. To produce a note of an octave higher than its fundamental, the frequency must be doubled. This can be achieved by reducing the mass per unit length of the string.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>38","subject":"Physics","year":"2006","type":"Objective","topic":"GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY","question":"The acceleration due to gravity may be defined as the force","images":[],"options":{"A":"of attraction of the sun on the earth","B":"with which the earth revolves around the sun","C":"with which the earth attracts one-kilogram mass","D":"of the moon on the earth"},"answer":"C","explanation":"The acceleration due to gravity is defined as the force with which the earth attracts a one-kilogram mass. This is a fundamental concept in physics, specifically in the study of gravity. The force of gravity is a measure of the gravitational attraction between two objects, in this case, the earth and a one-kilogram mass.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>39","subject":"Physics","year":"2006","type":"Objective","topic":"ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.","question":"An electron of mass m and charge e enters a uniform electric field between two metal plates P and Q separated by a distance d. P is maintained at a potential V while Q is earthed. Determine an expression for the magnitude of the acceleration of the electron through the field.","images":[],"options":{"A":"eV/md","B":"d/meV","C":"md/eV","D":"e/Vmd"},"answer":"A","explanation":"The force on the electron due to the electric field is given by F = eE, where E is the electric field strength. The electric field strength is given by E = V/d. Therefore, the force on the electron is F = eV/d. According to Newton's second law, F = ma, where m is the mass of the electron and a is its acceleration. Therefore, a = F/m = eV/md. Hence, the magnitude of the acceleration of the electron through the field is eV/md.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>40","subject":"Physics","year":"2006","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"Which of the following factors does not affect the capacitance of a parallel plate capacitor?","images":[],"options":{"A":"Area of the plates","B":"Nature of the surface of the plates","C":"Distance of separation between the plates","D":"Nature of the insulating material between the plates"},"answer":"B","explanation":"The capacitance of a parallel plate capacitor is given by the formula C = \u03b5A/d, where \u03b5 is the permittivity of the insulating material, A is the area of one of the plates, and d is the distance between the plates. Therefore, the capacitance is affected by the area of the plates, the distance of separation between the plates, and the nature of the insulating material between the plates. The nature of the surface of the plates does not affect the capacitance.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>41","subject":"Physics","year":"2006","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"The equivalent capacitance of a 3\u00b5F capacitor and a 6\u00b5F capacitor connected in parallel is","images":[],"options":{"A":"2.0\u00b5F","B":"3.0\u00b5F","C":"4.5\u00b5F","D":"9.0\u00b5F"},"answer":"D","explanation":"The capacitance, C1 = 3\u00b5F  The capacitance, C2 = 6\u00b5F  Equivalent capacitance, CT = ?  CT = C1 + C2  CT = 3 + 6   = 9.0\u00b5F","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>42","subject":"Physics","year":"2006","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"A cell of e.m.f 1.5V and internal resistance 1.0 \u03a9 is connected to two resistors of resistances 2.0\u03a9 and 3.0\u03a9 in series. Calculate the current through the resistors.","images":[],"options":{"A":"0.25A","B":"0.30A","C":"0.35A","D":"0.50A"},"answer":"A","explanation":"Given:  The e.m.f of the cell, E = 1.5V  The internal resistance, r = 1.0\u03a9  The Load, R1 = 2.0\u03a9  The Load = R2 = 3.0\u03a9  The Effective Load, = R1 + R2 (Since they are in series) = 2 + 3 = 5.0\u03a9  Recall: E = I(R + r)  \u2234 1.5 = I(5 + 1)  1.5 = 6I  I = 0.25A","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>43","subject":"Physics","year":"2006","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"An electric lamp rated 120W in used on a 240 Vrms, calculate the resistance of its filament.","images":[],"options":{"A":"480\u03a9","B":"360\u03a9","C":"60\u03a9","D":"2\u03a9"},"answer":"A","explanation":"The power rating, P = 120W  The root mean square, voltage, Vr.m.s = 240   The resistance, R of the filament is unknown  Recall:P=V2R  120=(240)2R  120R = 576 \u00d7 102  R = 480\u03a9","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>44","subject":"Physics","year":"2006","type":"Objective","topic":"MAGNETIC FIELD : PROPERTIES OF MAGNETS AND MAGNETIC MATERIALS","question":"Which of the following statements about a bar magnet is correct?","images":[],"options":{"A":"Iron filings cling uniformly along the length of the bar magnet","B":"The magnetic properties are more pronounced at the middle of a magnet","C":"It is impossible to have the same poles at the ends of a magnet","D":"The magnetic properties are more pronounced at points near the ends of the bar."},"answer":"D","explanation":"The magnetic properties of a bar magnet are more pronounced at points near the ends of the bar. These ends are called poles of the magnet. The region around the poles has the strongest magnetic effect, hence iron filings will tend to gather more at the poles than along the length of the magnet.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2006>45","subject":"Physics","year":"2006","type":"Objective","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"The force experienced by a current-carrying conductor moving in a magnetic field is employed in the working of the   I. moving coil ammeter II. electric bell III. electric motor  Which of the statements above are correct?","images":[],"options":{"A":"I and II only","B":"II and III only","C":"I and III only","D":"I, II and III"},"answer":"C","explanation":"The force experienced by a current-carrying conductor moving in a magnetic field is employed in the working of I and III.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2006>46","subject":"Physics","year":"2006","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"The breaking up of an atomic nucleus into two fragments of nearly equal sizes is known as","images":[],"options":{"A":"nuclear fusion","B":"nuclear fission","C":"thermonuclear reaction","D":"natural radioactivity"},"answer":"B","explanation":"The breaking up of an atomic nucleus into two fragments of nearly equal sizes is known as nuclear fission. In nuclear fission, the nucleus of an atom splits into two smaller fragments. This process often produces free neutrons and photons (in the form of gamma rays), and releases a large amount of energy.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>47","subject":"Physics","year":"2006","type":"Objective","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"A 500kV is applied across an X-ray tube. Calculate the maximum velocity of the electrons produced.  [Me = 9.1 \u00d7 10-31kg, e = 1.6 \u00d7 10-19C]","images":[],"options":{"A":"4.2 \u00d7 108 ms-1","B":"1.8 \u00d7 108 ms-1","C":"4.2 \u00d7 105 ms-1","D":"1.8 \u00d7 105 ms-1"},"answer":"A","explanation":"Given:  - The voltage applied = 500kV  - The maximum velocity of electrons = Vmax  Mass of electrons = 9.1 \u00d7 10-31kg. The charge of electron = 1.6 \u00d7 10-19C.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>48","subject":"Physics","year":"2006","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"A radioactive substance of mass 768g has a half life of 3 years. After how many years does this substance leave only 6g undecayed?","images":[],"options":{"A":"21","B":"18","C":"15","D":"12"},"answer":"A","explanation":"- The initial mass given =768g  - Half-life = 3 years    \u2234 The decay process will take place 7 times before it decays to 6g.  \u2234 It will take (7 \u00d7 3) years = 21 years.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>49","subject":"Physics","year":"2006","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Fusion is not usually used for generating electric power because","images":[],"options":{"A":"no energy is released when fusion takes place","B":"very high temperatures are required to initiate fusion reaction","C":"the raw materials needed are not easily available","D":"heavy nuclei are involved"},"answer":"B","explanation":"Fusion is not usually used for generating electric power because very high temperature are required to initiate fusion reaction.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2006>50","subject":"Physics","year":"2006","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"An atom 23491P emits a gamma radiation. The resultant nuclide is","images":[],"options":{"A":"23490Th","B":"23489Ac","C":"23090Th","D":"23491Pa"},"answer":"D","explanation":"Gamma radiation does not change the atomic number or the mass number of an atom. It only involves the emission of high energy photons from the nucleus. Therefore, the resultant nuclide after the emission of gamma radiation from 23491P would still be 23491P. However, the symbol for the element with atomic number 91 is Pa (Protactinium), not P. Therefore, option 4 is correct.","marks":"1","difficulty":"3"}];